mapper.select:
SELECT t.*, t1.real_name create_user_name FROM kb_category t LEFT OUTER JOIN castle_sys_user t1 ON t.create_user = t1.id WHERE t.is_deleted = 2
AND t.id like concat('%',#{kbCategoryEntity.id},'%')
AND t.name like concat('%',#{kbCategoryEntity.name},'%')
AND t.sw_id = #{kbCategoryEntity.swId}
AND t.sort = #{kbCategoryEntity.sort}
AND t.status = #{kbCategoryEntity.status}
AND t.create_time like concat('%',#{kbCategoryEntity.createTime},'%')
AND t.create_user like concat('%',#{kbCategoryEntity.createUser},'%')
AND t.update_user like concat('%',#{kbCategoryEntity.updateUser},'%')
AND t.update_time like concat('%',#{kbCategoryEntity.updateTime},'%')
AND t.is_deleted like concat('%',#{kbCategoryEntity.isDeleted},'%')
order by create_time desc
limit #{map.offset},#{map.rows}

select distinct ct.* from kb_category ct join kb_warehouse_auth au on ((ct.id = au.wh_id and au.category = 01 and au.status = 1) or (ct.id = au.wh_id and au.category = 01 and au.status = 2) or (ct.id = au.wh_id and au.category = 01 and au.status = 3) or (ct.sw_id = au.wh_id and au.category = 02 and au.status = 1) or (ct.sw_id = au.wh_id and au.category = 02 and au.status = 2) or (ct.sw_id = au.wh_id and au.category = 02 and au.status = 3)) left join kb_groups_user groupu on groupu.group_id = au.user_id and au.status = 2 left join castle_sys_dept dept on(dept.id = au.user_id or dept.parents like concat('%',au.user_id,'%')) and au.status = 3 join castle_sys_user user on (au.user_id = user.id or (user.id = groupu.user_id) or (user.dept_id = dept.id)) where au.is_deleted = 2 and ct.is_deleted = 2 and user.id= #{uid}
and ct.sw_id =#{wh_id}
and au.kb_auth in (
#{kb_auth}
) order by ct.sort desc, ct.create_time desc

select distinct ct.name, ct.id,sw.name as swName,sw.id as swId from kb_category ct join kb_basic basic on ct.id = basic.category_id join kb_warehouse_auth au on ((basic.id = au.wh_id and au.category = 01 and au.status = 1) or (basic.id = au.wh_id and au.category = 01 and au.status = 2) or (basic.id = au.wh_id and au.category = 01 and au.status = 3) or (ct.sw_id = au.wh_id and au.category = 02 and au.status = 1) or (ct.sw_id = au.wh_id and au.category = 02 and au.status = 2) or (ct.sw_id = au.wh_id and au.category = 02 and au.status = 3)) left join kb_groups_user groupu on groupu.group_id = au.user_id left join (select dept.id, user.id uid,dept.parents from castle_sys_dept dept join castle_sys_user user on user.dept_id = dept.id ) dept on (dept.id = au.user_id or dept.parents like concat('%',au.user_id,'%')) join kb_subject_warehouse sw on sw.id = ct.sw_id where ct.is_deleted = 2 and basic.is_deleted = 2 and au.is_deleted = 2 and (au.user_id =#{uid} or groupu.user_id=#{uid} or dept.uid=#{uid}) and au.kb_auth in (
#{kb_auth}
) group by ct.name,ct.id,sw.name,sw.id order by count(ct.name) desc limit #{topCount}

select distinct ct.* from kb_category ct join kb_warehouse_auth au on ((ct.id = au.wh_id and au.category = 01 and au.status = 1) or (ct.id = au.wh_id and au.category = 01 and au.status = 2) or (ct.id = au.wh_id and au.category = 01 and au.status = 3) or (ct.sw_id = au.wh_id and au.category = 02 and au.status = 1) or (ct.sw_id = au.wh_id and au.category = 02 and au.status = 2) or (ct.sw_id = au.wh_id and au.category = 02 and au.status = 3)) left join kb_groups_user groupu on groupu.group_id = au.user_id left join castle_sys_dept dept on dept.id = au.user_id left join castle_sys_user user on user.dept_id = dept.id where ct.is_deleted = 2 and sw_id = #{swId} and (au.user_id = #{uid} or groupu.user_id = #{uid} or user.id = #{uid}) and au.kb_auth in (
#{kb_auth}
) order by ct.sort desc limit 2
